// ---- GET and POST Requests with Retrofit ----

// ---- API Service with GET and POST ----
interface PostApiService {
    // ---- GET requests ----
    @GET("posts")
    suspend fun getPosts(): List<Post>

    @GET("posts/{id}")
    suspend fun getPost(@Path("id") id: Int): Post

    @GET("posts")
    suspend fun getPostsByUser(@Query("userId") userId: Int): List<Post>

    // ---- POST request ----
    @POST("posts")
    suspend fun createPost(@Body post: CreatePostRequest): Post

    // ---- POST with headers ----
    @Headers(
        "Content-Type: application/json",
        "Authorization: Bearer token"
    )
    @POST("posts")
    suspend fun createPostWithAuth(@Body post: CreatePostRequest): Post
}

// ---- Request models ----
data class CreatePostRequest(
    val title: String,
    val body: String,
    val userId: Int
)

// ---- Repository with GET and POST ----
class PostRepository {
    private val api = RetrofitClient.postApi

    suspend fun getPosts(): List<Post> = api.getPosts()

    suspend fun getPost(id: Int): Post = api.getPost(id)

    suspend fun getPostsByUser(userId: Int): List<Post> = api.getPostsByUser(userId)

    suspend fun createPost(title: String, body: String, userId: Int): Post {
        val request = CreatePostRequest(title, body, userId)
        return api.createPost(request)
    }
}

// ---- ViewModel with GET and POST ----
class PostViewModel : ViewModel() {
    private val repository = PostRepository()

    data class UiState(
        val posts: List<Post> = emptyList(),
        val selectedPost: Post? = null,
        val isLoading: Boolean = false,
        val isSubmitting: Boolean = false,
        val error: String? = null,
        val success: Boolean = false
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    // ---- GET: Load posts ----
    fun loadPosts() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }

            try {
                val posts = repository.getPosts()
                _uiState.update { it.copy(
                    posts = posts,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Failed to load posts",
                    isLoading = false
                )}
            }
        }
    }

    // ---- GET: Load single post ----
    fun loadPost(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }

            try {
                val post = repository.getPost(id)
                _uiState.update { it.copy(
                    selectedPost = post,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Failed to load post",
                    isLoading = false
                )}
            }
        }
    }

    // ---- GET: Posts by user ----
    fun loadPostsByUser(userId: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }

            try {
                val posts = repository.getPostsByUser(userId)
                _uiState.update { it.copy(
                    posts = posts,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Failed to load posts",
                    isLoading = false
                )}
            }
        }
    }

    // ---- POST: Create post ----
    fun createPost(title: String, body: String, userId: Int = 1) {
        viewModelScope.launch {
            _uiState.update { it.copy(isSubmitting = true, error = null, success = false) }

            try {
                val newPost = repository.createPost(title, body, userId)
                _uiState.update { it.copy(
                    posts = listOf(newPost) + it.posts,
                    isSubmitting = false,
                    success = true
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Failed to create post",
                    isSubmitting = false
                )}
            }
        }
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }

    fun clearSuccess() {
        _uiState.update { it.copy(success = false) }
    }
}

// ---- UI Screen ----
@Composable
fun PostScreen() {
    val viewModel: PostViewModel = viewModel()
    val uiState by viewModel.uiState.collectAsState()

    var title by remember { mutableStateOf("") }
    var body by remember { mutableStateOf("") }

    Scaffold(
        topBar = { TopAppBar { Text("GET & POST Demo") } }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // ---- Loading ----
            if (uiState.isLoading || uiState.isSubmitting) {
                Box(
                    modifier = Modifier.fillMaxWidth().height(50.dp),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator()
                }
            }

            // ---- Error ----
            if (uiState.error != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = uiState.error ?: "",
                            color = MaterialTheme.colorScheme.onErrorContainer
                        )
                        Button(onClick = { viewModel.clearError() }) {
                            Text("Dismiss")
                        }
                    }
                }
            }

            // ---- Success ----
            if (uiState.success) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.primaryContainer
                    )
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = "✅ Post created successfully!",
                            color = MaterialTheme.colorScheme.onPrimaryContainer
                        )
                        Button(onClick = { viewModel.clearSuccess() }) {
                            Text("Dismiss")
                        }
                    }
                }
            }

            // ---- Selected post ----
            if (uiState.selectedPost != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = "Selected Post",
                            style = MaterialTheme.typography.titleMedium
                        )
                        Text(
                            text = uiState.selectedPost?.title ?: "",
                            style = MaterialTheme.typography.titleLarge
                        )
                        Text(
                            text = uiState.selectedPost?.body ?: ""
                        )
                    }
                }
            }

            // ---- Create post form ----
            Text(
                text = "Create Post",
                style = MaterialTheme.typography.titleMedium
            )

            OutlinedTextField(
                value = title,
                onValueChange = { title = it },
                label = { Text("Title") },
                modifier = Modifier.fillMaxWidth()
            )

            OutlinedTextField(
                value = body,
                onValueChange = { body = it },
                label = { Text("Body") },
                modifier = Modifier.fillMaxWidth(),
                minLines = 2
            )

            Button(
                onClick = {
                    if (title.isNotBlank() && body.isNotBlank()) {
                        viewModel.createPost(title, body)
                        title = ""
                        body = ""
                    }
                },
                modifier = Modifier.fillMaxWidth(),
                enabled = !uiState.isSubmitting
            ) {
                Text("Create Post")
            }

            // ---- Posts list ----
            LazyColumn(
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(uiState.posts) { post ->
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable {
                                viewModel.loadPost(post.id)
                            },
                        elevation = CardDefaults.cardElevation(2.dp)
                    ) {
                        Column(
                            modifier = Modifier.padding(16.dp)
                        ) {
                            Text(
                                text = post.title,
                                style = MaterialTheme.typography.titleMedium
                            )
                            Text(
                                text = post.body,
                                style = MaterialTheme.typography.bodyMedium,
                                maxLines = 2,
                                overflow = TextOverflow.Ellipsis
                            )
                        }
                    }
                }
            }

            // ---- Buttons ----
            Button(
                onClick = { viewModel.loadPosts() },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Load Posts (GET)")
            }

            Button(
                onClick = { viewModel.loadPostsByUser(1) },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Load Posts by User 1 (GET with Query)")
            }
        }
    }
}

