package com.example.getpost

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.lifecycle.ViewModel
import androidx.lifecycle.compose.viewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.*

data class Post(val id: Int, val title: String, val body: String, val userId: Int)
data class CreatePostRequest(val title: String, val body: String, val userId: Int)

interface PostApi {
    @GET("posts")
    suspend fun getPosts(): List<Post>

    @POST("posts")
    suspend fun createPost(@Body request: CreatePostRequest): Post
}

object RetrofitClient {
    private const val BASE_URL = "https://jsonplaceholder.typicode.com/"
    val api: PostApi = Retrofit.Builder()
        .baseUrl(BASE_URL)
        .addConverterFactory(GsonConverterFactory.create())
        .build()
        .create(PostApi::class.java)
}

data class UiState(
    val posts: List<Post> = emptyList(),
    val isLoading: Boolean = false,
    val isCreating: Boolean = false,
    val success: Boolean = false,
    val error: String? = null
)

class PostViewModel : ViewModel() {
    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    fun loadPosts() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                val posts = RetrofitClient.api.getPosts()
                _uiState.update { it.copy(posts = posts, isLoading = false) }
            } catch (e: Exception) {
                _uiState.update { it.copy(error = e.message, isLoading = false) }
            }
        }
    }

    fun createPost(title: String, body: String) {
        viewModelScope.launch {
            _uiState.update { it.copy(isCreating = true, error = null, success = false) }
            try {
                val request = CreatePostRequest(title, body, 1)
                val newPost = RetrofitClient.api.createPost(request)
                _uiState.update {
                    it.copy(
                        posts = listOf(newPost) + it.posts,
                        isCreating = false,
                        success = true
                    )
                }
            } catch (e: Exception) {
                _uiState.update { it.copy(error = e.message, isCreating = false) }
            }
        }
    }

    fun clearSuccess() {
        _uiState.update { it.copy(success = false) }
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

@Composable
fun GetPostApp() {
    val viewModel: PostViewModel = viewModel()
    val uiState by viewModel.uiState.collectAsState()
    var title by remember { mutableStateOf("") }
    var body by remember { mutableStateOf("") }

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        if (uiState.isLoading) CircularProgressIndicator()
        if (uiState.isCreating) CircularProgressIndicator()
        if (uiState.success) {
            Card(
                modifier = Modifier.fillMaxWidth(),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.primaryContainer
                )
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text("✅ Post created!", color = MaterialTheme.colorScheme.onPrimaryContainer)
                    Button(onClick = { viewModel.clearSuccess() }) { Text("Dismiss") }
                }
            }
        }
        if (uiState.error != null) {
            Card(
                modifier = Modifier.fillMaxWidth(),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.errorContainer
                )
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text(uiState.error ?: "", color = MaterialTheme.colorScheme.onErrorContainer)
                    Button(onClick = { viewModel.clearError() }) { Text("Dismiss") }
                }
            }
        }

        OutlinedTextField(value = title, onValueChange = { title = it }, label = { Text("Title") })
        OutlinedTextField(value = body, onValueChange = { body = it }, label = { Text("Body") })
        Button(
            onClick = { if (title.isNotBlank() && body.isNotBlank()) viewModel.createPost(title, body) },
            modifier = Modifier.fillMaxWidth(),
            enabled = !uiState.isCreating
        ) {
            Text("Create Post (POST)")
        }

        LazyColumn(verticalArrangement = Arrangement.spacedBy(4.dp)) {
            items(uiState.posts.take(5)) { post ->
                Card(modifier = Modifier.fillMaxWidth(), elevation = CardDefaults.cardElevation(2.dp)) {
                    Column(modifier = Modifier.padding(8.dp)) {
                        Text(post.title, style = MaterialTheme.typography.titleMedium)
                        Text(post.body, style = MaterialTheme.typography.bodyMedium)
                    }
                }
            }
        }

        Button(onClick = { viewModel.loadPosts() }, modifier = Modifier.fillMaxWidth()) {
            Text("Load Posts (GET)")
        }
    }
}
